**Cooldown Timer**
====================

### Overview

A simple cooldown timer that prevents repeated actions within a specified time frame.

### Code

```javascript
class CooldownTimer {
  constructor(duration) {
    this.duration = duration; // cooldown duration in milliseconds
    this.lastUse = 0; // timestamp of last use
  }

  isReady() {
    const currentTime = Date.now();
    return currentTime - this.lastUse >= this.duration;
  }

  use() {
    if (this.isReady()) {
      this.lastUse = Date.now();
      return true;
    }
    return false;
  }
}

// Example usage
const cooldown = new CooldownTimer(5000); // 5-second cooldown

function exampleAction() {
  if (cooldown.use()) {
    console.log("Action executed!");
  } else {
    console.log("Cooldown not ready yet.");
  }
}

// Test the cooldown timer
exampleAction(); // executes immediately
setTimeout(exampleAction, 2000); // executes after 2 seconds, still on cooldown
setTimeout(exampleAction, 6000); // executes after 6 seconds, ready to use again

